const input = $input.first().json;
const workflowName = String(input.workflowName || 'DB row listener').trim().slice(0, 128);
const tableName = String(input.tableName || '').trim();
const schemaName = String(input.schemaName != null && String(input.schemaName).trim() ? input.schemaName : 'public').trim();
const description = String(input.description || ('Postgres Trigger on ' + schemaName + '.' + tableName)).slice(0, 255);
if (!tableName) throw new Error('tableName is required.');
const safeName = workflowName.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const safeTable = tableName.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const safeSchema = schemaName.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const slug = workflowName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') || 'pg-row-listener';

const sdkCode = `import { workflow, node, trigger, expr } from "@n8n/workflow-sdk";

const rowTrigger = trigger({
  type: "n8n-nodes-base.postgresTrigger",
  version: 1,
  config: {
    name: "On row change",
    credentials: {
      postgres: { id: "PostgresStarter001", name: "Supabase Postgres (configure credential in n8n)" },
    },
    parameters: {
      triggerMode: "createTrigger",
      schema: { __rl: true, mode: "name", value: "${safeSchema}" },
      tableName: { __rl: true, mode: "name", value: "${safeTable}" },
      firesOn: "INSERT",
      additionalFields: {},
      options: {},
    },
  },
});

const logEvent = node({
  type: "n8n-nodes-base.set",
  version: 3.4,
  config: {
    name: "Record event",
    parameters: {
      mode: "manual",
      assignments: {
        assignments: [
          { id: "s", name: "source", value: "postgres-trigger", type: "string" },
          { id: "p", name: "payload", value: expr("{{ $json }}"), type: "object" },
        ],
      },
    },
  },
});

export default workflow("${slug}", "${safeName}").add(rowTrigger).to(logEvent);`;

return [{
  json: {
    workflowName,
    tableName,
    schemaName,
    description,
    sdkCode,
    validateRpc: { jsonrpc: '2.0', id: 1, method: 'tools/call', params: { name: 'validate_workflow', arguments: { code: sdkCode } } },
    createRpc: { jsonrpc: '2.0', id: 2, method: 'tools/call', params: { name: 'create_workflow_from_code', arguments: { code: sdkCode, name: workflowName, description } } },
  },
}];

function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/?
/).find((line) => line.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP validate response: ' + text.slice(0, 400));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const contentText = payload.result?.content?.[0]?.text;
  return contentText ? JSON.parse(contentText) : (payload.result?.structuredContent || {});
}
const http = $input.first().json;
const validation = parseMcpSse(http.body ?? http.data ?? '');
if (!validation.valid) throw new Error('Workflow validation failed: ' + JSON.stringify(validation));
const built = $('Build SDK Payload').first().json;
return [{ json: { ...built, validation } }];

